"use strict";(self.webpackChunkics_training=self.webpackChunkics_training||[]).push([[4464],{9800(e,t,a){a.r(t),a.d(t,{assets:()=>d,contentTitle:()=>c,default:()=>m,frontMatter:()=>l,metadata:()=>n,toc:()=>h});const n=JSON.parse('{"id":"advanced/practice/module-6","title":"Advanced Module 6 Practice: Statute of Limitations and Final Decisions","description":"Falcon Defense Contractors has the following ICS history:","source":"@site/docs/advanced/practice/module-6.md","sourceDirName":"advanced/practice","slug":"/advanced/practice/module-6","permalink":"/advanced/practice/module-6","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"title":"Advanced Module 6 Practice: Statute of Limitations and Final Decisions"},"sidebar":"tutorialSidebar","previous":{"title":"Advanced Module 5 Practice: Responding to DCAA Findings","permalink":"/advanced/practice/module-5"},"next":{"title":"Advanced Module 7 Practice: ICS in M&A and Novation Scenarios","permalink":"/advanced/practice/module-7"}}');var i=a(4848),r=a(8453),s=a(5960),o=a(5622);const l={title:"Advanced Module 6 Practice: Statute of Limitations and Final Decisions"},c=void 0,d={},h=[];function u(e){const t={a:"a",hr:"hr",li:"li",p:"p",ul:"ul",...(0,r.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsxs)(s.A,{moduleId:"module6",stepId:"1",title:"Step 1: Identify When Claims Accrue",children:[(0,i.jsx)("p",{children:(0,i.jsx)(t.p,{children:"Falcon Defense Contractors has the following ICS history:"})}),(0,i.jsx)("p",{children:(0,i.jsxs)(t.ul,{children:["\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)("strong",{children:"Year 1:"})," ICS submitted January 15, Year 2. Final rates established June 3, Year 5. DCAA questioned $90,000 in costs during the audit (identified in the final audit report issued April 1, Year 5).",(0,i.jsx)("br",{})]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)("strong",{children:"Year 2:"})," ICS submitted June 28, Year 3. Still no final rates established as of today (Year 10).",(0,i.jsx)("br",{})]}),"\n",(0,i.jsxs)(t.li,{children:[(0,i.jsx)("strong",{children:"Year 3:"})," ICS submitted June 30, Year 4. Final rates established March 12, Year 7. Falcon believes it was underbilled by $145,000 based on the final rates."]}),"\n"]})}),(0,i.jsx)(o.A,{answer:"Year 1 government claim ($90,000 questioned costs): The government's claim accrued when the costs were incurred (Year 1) and the government knew of them (the audit report was issued April 1, Year 5, when DCAA formally identified the questioned costs). Courts have generally held that the government's claim accrues when the government knew or should have known of the unallowable costs \u2014 in practice, this is often tied to when the ICS was submitted or when the audit discovered the issue. If accrual is tied to the April 1, Year 5 final report date, the government has until approximately April 1, Year 11 to assert a claim. Year 3 contractor underbilling claim ($145,000): The contractor's claim for underbilled amounts accrues when final rates are established (because that is when the contractor can calculate the underbilling with certainty). Final rates were established March 12, Year 7. The contractor has until approximately March 12, Year 13 to file a certified claim. The contractor should file well before that deadline.",children:(0,i.jsx)(t.p,{children:"For the Year 1 government claim and the Year 3 contractor underbilling claim, identify when each claim likely accrued and when the six-year CDA window closes. What are the practical filing deadlines for each party?"})}),(0,i.jsx)(o.A,{answer:"Year 2 is the most dangerous situation. With no final rates established as of Year 10 \u2014 seven years after ICS submission \u2014 the year is still open. The risks: (1) Document retention: without final payment on any contract covered by Year 2, the FAR three-year records retention clock has not started. Falcon must retain all Year 2 records indefinitely until the year closes. If records have been destroyed (e.g., old invoices, timesheets), Falcon faces potential questioned costs for undocumented items across an entire year. (2) Government claims: depending on when specific cost items accrued, some may still be within the six-year window while others may not be \u2014 creating complex legal questions if the audit happens now. (3) Falcon's own claims: if Falcon was underbilled in Year 2, its claim accrual may have run before final rates were established, potentially barring the claim. Falcon should proactively engage the ACO to push Year 2 to resolution \u2014 either through a negotiated settlement, quick-close (if available), or by forcing DCAA to complete the audit.",children:(0,i.jsx)(t.p,{children:"What are the specific risks Falcon faces by having Year 2 still open in Year 10? What should Falcon do proactively?"})})]}),"\n",(0,i.jsxs)(s.A,{moduleId:"module6",stepId:"2",title:"Step 2: Certified Claims and COFD Timing",children:[(0,i.jsx)("p",{children:(0,i.jsx)(t.p,{children:"On March 1, Year 8, Falcon's counsel submits a certified claim to the contracting officer for $145,000 in Year 3 underbillings. The claim is certified by Falcon's CFO. The CO acknowledges receipt on March 5. By June 1 (nearly 90 days later), no COFD has been issued and the CO has not communicated about the timeline."})}),(0,i.jsx)(o.A,{answer:"For a claim over $100,000, the CO must issue a COFD within 60 days of receiving a properly certified claim \u2014 or within that 60-day period provide written notice of a specific date by which the decision will be issued. The 60-day window from March 5 receipt expired on May 4. No COFD was issued, and no written notice of an extended timeline was provided. This constitutes a 'deemed denial' under the CDA. As of May 4 (or reasonably shortly thereafter once Falcon confirms no COFD or notice was received), Falcon may treat the claim as denied and immediately file an appeal at a Board of Contract Appeals or the Court of Federal Claims without waiting for an actual COFD. Falcon does not need a formal denial letter to appeal \u2014 the deemed denial gives Falcon full appeal rights.",children:(0,i.jsx)(t.p,{children:"Has the CO's deadline to issue a COFD passed? What legal rights does Falcon now have under the CDA?"})}),(0,i.jsx)(o.A,{answer:"Falcon has two options: (1) Board of Contract Appeals (ASBCA for DoD contracts, or CBCA for civilian agencies): Falcon must file a written appeal within 90 days of the deemed denial. The appeal is less expensive and faster than Court of Federal Claims litigation, and the Board has deep expertise in government contract cost disputes. (2) Court of Federal Claims: Falcon can file suit within 12 months of the deemed denial. This path is more expensive but may be preferable for large claims or where Falcon wants the ability to conduct extensive discovery. Before filing, Falcon should ensure: the claim certification is properly executed (senior official, three required statements); all supporting documentation is organized; and the $145,000 calculation is precisely documented (showing final rates, provisional billing rates, and the mathematical underbilling on each contract). Filing a defective certification or an unsupported claim amount will cause immediate problems.",children:(0,i.jsx)(t.p,{children:"What are Falcon's two appeal forum options, and what are the deadlines for each from the deemed denial? What should Falcon verify before filing?"})})]}),"\n",(0,i.jsxs)(s.A,{moduleId:"module6",stepId:"3",title:"Step 3: Calculate CDA Interest",children:[(0,i.jsx)("p",{children:(0,i.jsx)(t.p,{children:"Falcon's $145,000 claim was submitted March 1, Year 8. The Board of Contract Appeals rules in Falcon's favor 28 months later (July 1, Year 10) and orders the government to pay the full $145,000. The applicable CDA interest rate has been 4.5% per year for the entire period (simplified for this exercise)."})}),(0,i.jsx)(o.A,{answer:"CDA interest accrues from the date the claim was submitted to the contracting officer (March 1, Year 8) until the date the government pays. The ruling was issued July 1, Year 10 \u2014 28 months after submission. At 4.5% per year simple interest: $145,000 \xd7 4.5% \xd7 (28/12 years) = $145,000 \xd7 4.5% \xd7 2.333 = $145,000 \xd7 0.105 = $15,225 in interest. Total recovery: $145,000 principal + $15,225 interest = $160,225. Note: if the government delays paying after the ruling, interest continues to accrue from the claim submission date through the actual payment date \u2014 not just to the ruling date. Falcon should ensure prompt payment after the ruling.",children:(0,i.jsx)(t.p,{children:"Calculate the total amount Falcon recovers including CDA interest. Show the interest calculation and identify the start and end dates for the interest accrual period."})}),(0,i.jsx)(o.A,{answer:"The interest provision serves two purposes: (1) It compensates Falcon for the time value of money \u2014 Falcon was entitled to the $145,000 in Year 7 when final rates were established, and the government had use of that money for 28+ months. Without interest, the government would have an incentive to delay payment indefinitely. (2) It deters the government from denying valid claims as a delay tactic. The interest rate (Treasury rate, adjusted semi-annually) is generally below commercial borrowing rates, so the provision is not punitive \u2014 it simply approximates the cost of money for the period of delay. For contractors, this means that submitting a large underbilling claim promptly after final rates are established (rather than waiting) maximizes the interest recovery if the claim is eventually paid. A contractor that waits two years after final rates to file a claim loses two years of interest accrual.",children:(0,i.jsx)(t.p,{children:"Why does the CDA provide for interest on contractor claims, and what practical lesson does this create for when contractors should file underbilling claims?"})})]}),"\n",(0,i.jsx)(t.hr,{}),"\n",(0,i.jsxs)(t.p,{children:[(0,i.jsx)(t.a,{href:"/advanced/flashcards/module-6",children:"\u2190 Flashcards"})," | ",(0,i.jsx)(t.a,{href:"/advanced/training/module-7",children:"Next Module \u2192"})]})]})}function m(e={}){const{wrapper:t}={...(0,r.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(u,{...e})}):u(e)}},5622(e,t,a){a.d(t,{A:()=>r});var n=a(6540),i=a(4848);function r(e){var t=e.children,a=e.answer,r=(0,n.useState)(!1),s=r[0],o=r[1];return(0,i.jsxs)("div",{style:{marginTop:8},children:[(0,i.jsx)("div",{children:t}),(0,i.jsx)("button",{style:{marginTop:8},onClick:function(){return o(!s)},children:s?"Hide answer":"Show answer"}),s&&(0,i.jsx)("div",{style:{marginTop:8,background:"#f7f7f7",padding:8,borderRadius:4},children:a})]})}},5960(e,t,a){a.d(t,{A:()=>r});var n=a(6540),i=a(4848);function r(e){e.moduleId,e.stepId;var t=e.title,a=e.children,r=(0,n.useState)(!1),s=r[0],o=r[1];return(0,i.jsxs)("div",{style:{border:"1px solid #eee",padding:12,borderRadius:6,marginBottom:12},children:[(0,i.jsxs)("div",{style:{display:"flex",justifyContent:"space-between",alignItems:"center"},children:[(0,i.jsx)("strong",{children:t}),s?(0,i.jsx)("button",{onClick:function(){return o(!1)},children:"Hide"}):(0,i.jsx)("button",{onClick:function(){return o(!0)},children:"Reveal"})]}),s&&(0,i.jsx)("div",{style:{marginTop:12},children:a})]})}},8453(e,t,a){a.d(t,{R:()=>s,x:()=>o});var n=a(6540);const i={},r=n.createContext(i);function s(e){const t=n.useContext(r);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),n.createElement(r.Provider,{value:t},e.children)}}}]);